fn greet(name: &str, times: u32) {
    for _ in 0..times {
        println!("Hello, {}!", name);
    }
}

fn main() {
    greet("Alice", 2);
    greet("Bob", 1);
}

fn square(x: i32) -> i32 {
    x * x
}

fn main() {
    println!("{}", square(4));
    println!("{}", square(10));
}

fn absolute(n: i32) -> i32 {
    if n < 0 { return -n; }
    n
}

fn main() {
    println!("{}", absolute(-5));
    println!("{}", absolute(3));
    println!("{}", absolute(0));
}

